var protocol = require("./companion-protocol.js");

function sendTemperature(value) {
    var appMessage = protocol.encodePhoneToWatchPayload("ProvideTemperature", value);
    if (!appMessage) {
        console.log("failed to encode phone-to-watch message");
        return;
    }

    Pebble.sendAppMessage(
        appMessage,
        function () {
            console.log("companion -> watch", JSON.stringify(appMessage));
        },
        function (error) {
            console.log("companion send failed:", JSON.stringify(error));
        }
    );
}

function decodeTemperature(bodyText) {
    var parsed;
    try {
        parsed = JSON.parse(bodyText);
    } catch (_parseError) {
        return null;
    }

    if (!parsed || !parsed.current) {
        return null;
    }

    var raw = parsed.current.temperature_2m;
    if (typeof raw !== "number" || !isFinite(raw)) {
        return null;
    }

    return Math.round(raw);
}

function requestWeather(locationCode) {
    var query = protocol.LOCATION_QUERY_BY_CODE[locationCode];
    if (!query) {
        console.log("unsupported location code:", locationCode);
        return;
    }

    var url = "https://api.open-meteo.com/v1/forecast?" + query + "&current=temperature_2m&forecast_days=1";
    var xhr = new XMLHttpRequest();
    xhr.timeout = 10000;

    xhr.onload = function () {
        if (xhr.status < 200 || xhr.status >= 300) {
            console.log("weather request failed with status", xhr.status);
            return;
        }

        var temperature = decodeTemperature(xhr.responseText);
        if (temperature === null) {
            console.log("weather response decode failed");
            return;
        }

        sendTemperature(temperature);
    };

    xhr.onerror = function () {
        console.log("weather request network error");
    };

    xhr.ontimeout = function () {
        console.log("weather request timeout");
    };

    xhr.open("GET", url);
    xhr.send();
}

function onAppMessage(event) {
    if (!event || !event.payload) {
        return;
    }

    var message = protocol.decodeWatchToPhonePayload(event.payload);
    if (!message || message.kind !== "RequestWeather") {
        return;
    }

    requestWeather(message.locationCode);
}

function init() {
    Pebble.addEventListener("appmessage", onAppMessage);
}

module.exports = {
    init: init
};
